import React from 'react';
import womenImg from '../assets/images/women .png';
import menImg   from '../assets/images/men.jpg';
import childImg from '../assets/images/child.jpg';
import './CategoryBanner.css';

const banners = [
  {
    id: 1,
    title: 'Women',
    sub: 'Spring 2025',
    img: womenImg,
    bg: '#f5f5f5',
    dark: false,
  },
  {
    id: 2,
    title: 'Men',
    sub: 'Spring 2025',
    img: menImg,
    bg: '#f5f5f5',
    dark: false,
  },
  {
    id: 3,
    title: 'Children',
    sub: 'Spring 2025',
    img: childImg,
    bg: '#7b7fc4',
    dark: true,
  },
];

export default function CategoryBanner() {
  return (
    <section className="cat-banner-section">
      {banners.map((b) => (
        <div
          key={b.id}
          className={`cat-banner-card ${b.dark ? 'dark' : ''}`}
          style={{ background: b.bg }}
        >
          {/* Left: text */}
          <div className="cat-banner-content">
            <h3 className="cat-banner-title">{b.title}</h3>
            <p className="cat-banner-sub">{b.sub}</p>
            {b.dark && (
              <button className="cat-banner-btn">SHOP NOW</button>
            )}
          </div>
          {/* Right: image */}
          <div className="cat-banner-img-wrap">
            <img src={b.img} alt={b.title} className="cat-banner-img" />
          </div>
        </div>
      ))}
    </section>
  );
}
